-- 50 milestone "fairytale chapter" phrases, unlocked every 5 visits (days 5..250).
-- day_number holds the visit milestone at which each chapter unlocks. These are
-- separate from the random daily pool (which uses day_number = null).
-- Idempotent: re-running updates the text rather than failing on unique day_number.
on conflict (day_number) do update set message = excluded.message, author = excluded.author;
